#include <stdio.h>
#include <stdlib.h>
#include <stdbool.h>

// Define maximum number of segments
#define MAX_SEGMENTS 10

// Segment table entry structure
typedef struct {
 int base; // Starting physical address
 int limit; // Length of segment
 char protection; // Protection bits: r=read, w=write, x=execute
 int valid; // Whether this segment is allocated
} SegmentEntry;

// Segment table for a process
typedef struct {
 SegmentEntry segments[MAX_SEGMENTS];
 int num_segments;
} SegmentTable;

// Initialize segment table
void init_segment_table(SegmentTable *st) {
 st->num_segments = 0;
 for (int i = 0; i < MAX_SEGMENTS; i++) {
 st->segments[i].valid = 0;
 }
}

// Add a segment to the segment table
void add_segment(SegmentTable *st, int seg_num, int base, int limit, char prot) {
 if (seg_num >= MAX_SEGMENTS) {
 printf("Error: Segment number %d exceeds maximum\n", seg_num);
 return;
 }

 st->segments[seg_num].base = base;
 st->segments[seg_num].limit = limit;
 st->segments[seg_num].protection = prot;
 st->segments[seg_num].valid = 1;

 if (seg_num >= st->num_segments) {
 st->num_segments = seg_num + 1;
 }

 printf("Added segment %d: base=%d, limit=%d, protection=%c\n", 
 seg_num, base, limit, prot);
}

// Translate logical address <segment, offset> to physical address
// Returns: physical address if successful, -1 if segmentation fault
int translate_address(SegmentTable *st, int segment, int offset) {
 // Step 1: Check if segment number is valid
 if (segment >= MAX_SEGMENTS || !st->segments[segment].valid) {
 printf("Error: Invalid segment number %d\n", segment);
 return -1;
 }

 // Get segment entry
 int base = st->segments[segment].base;
 int limit = st->segments[segment].limit;

 // Step 2: Check if offset is within segment bounds (limit check)
 if (offset >= limit) {
 printf("SEGMENTATION FAULT: Offset %d >= limit %d\n", offset, limit);
 return -1;
 }

 // Step 3: Calculate physical address
 int physical = base + offset;

 return physical;
}

// Display segment table
void display_segment_table(SegmentTable *st) {
 printf("\n========== SEGMENT TABLE ==========\n");
 printf("%-10s %-10s %-10s %-12s\n", "Segment", "Base", "Limit", "Protection");
 printf("----------------------------------------\n");

 for (int i = 0; i < st->num_segments; i++) {
 if (st->segments[i].valid) {
 printf("%-10d %-10d %-10d %-12c\n", 
 i, 
 st->segments[i].base, 
 st->segments[i].limit,
 st->segments[i].protection);
 }
 }
 printf("========================================\n\n");
}

// Test address translation with detailed output
void test_translation(SegmentTable *st, int seg_num, int offset) {
 printf("Translating logical address <%d, %d>:\n", seg_num, offset);
 printf("----------------------------------------\n");

 if (seg_num >= MAX_SEGMENTS || !st->segments[seg_num].valid) {
 printf(" Result: INVALID SEGMENT\n\n");
 return;
 }

 int base = st->segments[seg_num].base;
 int limit = st->segments[seg_num].limit;

 printf(" Segment %d: base = %d, limit = %d\n", seg_num, base, limit);
 printf(" Offset = %d\n", offset);

 // Bound check
 if (offset >= limit) {
 printf(" Check: %d >= %d ? YES → SEGMENTATION FAULT\n", offset, limit);
 printf(" Result: TRAP (segmentation fault)\n\n");
 return;
 }

 printf(" Check: %d < %d ? YES → Valid address\n", offset, limit);

 int physical = base + offset;
 printf(" Physical = base + offset = %d + %d = %d\n", base, offset, physical);
 printf(" Result: Physical address = %d\n\n", physical);
}

int main() {
 printf("========================================\n");
 printf("SEGMENTATION MEMORY MANAGEMENT - C\n");
 printf("========================================\n");

 // Create and initialize segment table
 SegmentTable st;
 init_segment_table(&st);

 // Set up segment table (from textbook example)
 // Segment | Base | Limit
 // 0 | 219 | 600
 // 1 | 2300 | 14
 // 2 | 90 | 100
 // 3 | 1327 | 580
 // 4 | 1952 | 96

 printf("Setting up segment table:\n");
 add_segment(&st, 0, 219, 600, 'r'); // Code segment
 add_segment(&st, 1, 2300, 14, 'r'); // Symbol table
 add_segment(&st, 2, 90, 100, 'r'); // Array
 add_segment(&st, 3, 1327, 580, 'r'); // Heap
 add_segment(&st, 4, 1952, 96, 'r'); // Stack

 // Display the segment table
 display_segment_table(&st);

 // Test Case 1: <2, 53> from textbook
 // Expected: Physical = 90 + 53 = 143
 printf("=== TEST CASE 1: Valid address ===\n");
 test_translation(&st, 2, 53);

 // Test Case 2: <3, 852> from textbook
 // Expected: SEGMENTATION FAULT (852 >= 580)
 printf("=== TEST CASE 2: Invalid address (segmentation fault) ===\n");
 test_translation(&st, 3, 852);

 // Additional test cases
 printf("=== ADDITIONAL TESTS ===\n");
 test_translation(&st, 0, 0); // First byte of segment 0
 test_translation(&st, 0, 599); // Last valid byte of segment 0
 test_translation(&st, 0, 600); // Beyond limit - fault
 test_translation(&st, 4, 95); // Last valid of segment 4
 test_translation(&st, 5, 10); // Invalid segment

 return 0;
}
